from qiskit import QuantumCircuit
from qiskit.quantum_info import Statevector
import numpy as np
from typing import Dict, List, Optional, Callable

class BreakpointDebugger:
    """Quantum circuit debugger with breakpoint support."""

    def __init__(self, circuit: QuantumCircuit):
        self.circuit = circuit.remove_final_measurements(inplace=False)
        self.n_qubits = circuit.num_qubits
        self.current_step = 0
        self.breakpoints: Dict[int, Dict] = {}
        self.conditions: Dict[int, Callable] = {}
        self._build_states()

    def _build_states(self):
        """Pre-compute states at each step."""
        self.states = [Statevector.from_int(0, 2**self.n_qubits).data]
        partial = QuantumCircuit(self.n_qubits)
        for inst, qargs, cargs in self.circuit.data:
            qubit_indices = [q._index for q in qargs]
            partial.append(inst, qubit_indices)
            sv = Statevector.from_instruction(partial)
            self.states.append(sv.data)

    def add_breakpoint(self, gate_index: int, name: str = None):
        """Add simple breakpoint."""
        self.breakpoints[gate_index] = {
            'name': name or f'BP_{gate_index}',
            'enabled': True,
            'hits': 0
        }
        print(f"Breakpoint added at gate {gate_index}")

    def add_conditional_breakpoint(self, gate_index: int,
                                   condition: Callable[[np.ndarray], bool],
                                   name: str = None):
        """Add conditional breakpoint."""
        self.add_breakpoint(gate_index, name)
        self.conditions[gate_index] = condition

    def remove_breakpoint(self, gate_index: int):
        """Remove breakpoint."""
        if gate_index in self.breakpoints:
            del self.breakpoints[gate_index]
            self.conditions.pop(gate_index, None)
            print(f"Breakpoint removed from gate {gate_index}")

    def toggle_breakpoint(self, gate_index: int):
        """Enable/disable breakpoint."""
        if gate_index in self.breakpoints:
            self.breakpoints[gate_index]['enabled'] = not self.breakpoints[gate_index]['enabled']
            status = "enabled" if self.breakpoints[gate_index]['enabled'] else "disabled"
            print(f"Breakpoint at gate {gate_index} {status}")

    def _check_breakpoint(self, gate_index: int) -> bool:
        """Check if breakpoint should trigger."""
        if gate_index not in self.breakpoints:
            return False
        bp = self.breakpoints[gate_index]
        if not bp['enabled']:
            return False
        if gate_index in self.conditions:
            state = self.states[gate_index]
            if not self.conditions[gate_index](state):
                return False
        bp['hits'] += 1
        return True

    def continue_execution(self) -> Optional[int]:
        """Continue until next breakpoint."""
        while self.current_step < len(self.circuit.data):
            self.current_step += 1
            if self._check_breakpoint(self.current_step):
                return self.current_step
        return None

    def step(self) -> Optional[Dict]:
        """Execute one step."""
        if self.current_step >= len(self.circuit.data):
            return None
        self.current_step += 1
        inst, qargs, _ = self.circuit.data[self.current_step - 1]
        return {
            'step': self.current_step,
            'gate': inst.name,
            'qubits': [q._index for q in qargs],
            'state': self.states[self.current_step]
        }

    def list_breakpoints(self):
        """Display all breakpoints."""
        print("\nBreakpoints:")
        print("-" * 50)
        if not self.breakpoints:
            print("  No breakpoints set")
            return
        for idx, bp in sorted(self.breakpoints.items()):
            status = "ON" if bp['enabled'] else "OFF"
            cond = " (conditional)" if idx in self.conditions else ""
            print(f"  [{status}] Gate {idx}: {bp['name']}{cond} (hits: {bp['hits']})")

    def get_state_at(self, step: int) -> np.ndarray:
        """Get state at specific step."""
        if step < 0 or step >= len(self.states):
            raise IndexError(f"Step {step} out of range")
        return self.states[step]

from qiskit import QuantumCircuit
from qiskit.quantum_info import Statevector, DensityMatrix, partial_trace
import numpy as np
from typing import Dict, List, Tuple

class StateInspector:
    """Comprehensive quantum state inspection tool."""

    def __init__(self, n_qubits: int):
        self.n_qubits = n_qubits

    def get_amplitudes(self, state: np.ndarray,
                       threshold: float = 1e-10) -> Dict[str, complex]:
        """Get non-zero amplitudes with basis state labels."""
        amplitudes = {}
        for i, amp in enumerate(state):
            if abs(amp) > threshold:
                basis = format(i, f'0{self.n_qubits}b')
                amplitudes[basis] = complex(amp)
        return amplitudes

    def get_phases(self, state: np.ndarray,
                   threshold: float = 1e-10) -> Dict[str, Tuple[float, float]]:
        """Get phases in radians and degrees."""
        phases = {}
        for i, amp in enumerate(state):
            if abs(amp) > threshold:
                basis = format(i, f'0{self.n_qubits}b')
                phase_rad = np.angle(amp)
                phase_deg = np.degrees(phase_rad)
                phases[basis] = (phase_rad, phase_deg)
        return phases

    def analyze_entanglement(self, state: np.ndarray) -> Dict:
        """Analyze entanglement structure."""
        if self.n_qubits < 2:
            return {'message': 'Single qubit - no entanglement'}

        dm = DensityMatrix(state)
        results = {}

        for q in range(self.n_qubits):
            trace_out = [i for i in range(self.n_qubits) if i != q]
            reduced = partial_trace(dm, trace_out)
            purity = np.real(np.trace(reduced.data @ reduced.data))
            results[q] = {
                'purity': float(purity),
                'is_entangled': purity < 0.99
            }

        return results

    def get_statistics(self, state: np.ndarray) -> Dict:
        """Calculate statistical properties."""
        probs = np.abs(state) ** 2
        nonzero_probs = probs[probs > 1e-10]

        entropy = 0
        if len(nonzero_probs) > 0:
            entropy = float(-np.sum(nonzero_probs * np.log2(nonzero_probs)))

        return {
            'num_nonzero': len(nonzero_probs),
            'max_probability': float(np.max(probs)),
            'min_nonzero_probability': float(np.min(nonzero_probs)) if len(nonzero_probs) > 0 else 0,
            'entropy': entropy
        }

    def compare_states(self, state1: np.ndarray,
                       state2: np.ndarray) -> Dict:
        """Compare two states."""
        fidelity = abs(np.vdot(state1, state2)) ** 2

        changes = []
        for i in range(len(state1)):
            diff = abs(state1[i] - state2[i])
            if diff > 1e-10:
                basis = format(i, f'0{self.n_qubits}b')
                changes.append({
                    'basis': basis,
                    'state1_amp': complex(state1[i]),
                    'state2_amp': complex(state2[i]),
                    'prob_change': abs(state2[i])**2 - abs(state1[i])**2
                })

        return {
            'fidelity': float(fidelity),
            'num_differences': len(changes),
            'changes': changes
        }

    def full_inspection(self, state: np.ndarray) -> Dict:
        """Complete state inspection."""
        return {
            'amplitudes': self.get_amplitudes(state),
            'phases': self.get_phases(state),
            'entanglement': self.analyze_entanglement(state),
            'statistics': self.get_statistics(state)
        }

    def print_inspection(self, state: np.ndarray):
        """Print formatted inspection report."""
        inspection = self.full_inspection(state)

        print("\n" + "="*60)
        print("STATE INSPECTION REPORT")
        print("="*60)

        print("\nAMPLITUDES:")
        for basis, amp in sorted(inspection['amplitudes'].items()):
            prob = abs(amp)**2
            phase_rad, phase_deg = inspection['phases'][basis]
            print(f"  |{basis}>: {amp:.4f} (p={prob:.4f}, phase={phase_deg:.1f} deg)")

        print("\nSTATISTICS:")
        for key, value in inspection['statistics'].items():
            print(f"  {key}: {value:.4f}" if isinstance(value, float) else f"  {key}: {value}")

        print("\nENTANGLEMENT:")
        if isinstance(inspection['entanglement'], dict) and 'message' not in inspection['entanglement']:
            for q, data in inspection['entanglement'].items():
                status = "entangled" if data['is_entangled'] else "separable"
                print(f"  Qubit {q}: purity={data['purity']:.4f} ({status})")

from qiskit import QuantumCircuit
from qiskit.quantum_info import Statevector, DensityMatrix, partial_trace
import numpy as np
from typing import Dict, List, Optional, Callable
from datetime import datetime

class DebugSession:
    """Complete quantum debugging session manager."""

    def __init__(self, circuit: QuantumCircuit, name: str = "session"):
        self.name = name
        self.circuit = circuit.remove_final_measurements(inplace=False)
        self.n_qubits = circuit.num_qubits
        self.current_step = 0
        self.states = self._precompute_states()
        self.breakpoints: Dict[int, Dict] = {}
        self.snapshots: List[Dict] = []
        self.watches: Dict[str, Callable] = {}
        self.log: List[Dict] = []

    def _precompute_states(self) -> List[np.ndarray]:
        """Pre-compute all intermediate states."""
        states = [Statevector.from_int(0, 2**self.n_qubits).data]
        partial = QuantumCircuit(self.n_qubits)
        for inst, qargs, _ in self.circuit.data:
            qubit_indices = [q._index for q in qargs]
            partial.append(inst, qubit_indices)
            states.append(Statevector.from_instruction(partial).data)
        return states

    def add_breakpoint(self, gate_index: int, name: str = None):
        """Add breakpoint."""
        self.breakpoints[gate_index] = {
            'name': name or f'bp_{gate_index}',
            'enabled': True,
            'hits': 0
        }
        self._log(f"Breakpoint added at gate {gate_index}")

    def add_watch(self, name: str, expression: Callable[[np.ndarray], any]):
        """Add watch expression."""
        self.watches[name] = expression
        self._log(f"Watch added: {name}")

    def take_snapshot(self, label: str = None):
        """Save current state snapshot."""
        snap_label = label or f"snap_{len(self.snapshots)}"
        self.snapshots.append({
            'label': snap_label,
            'step': self.current_step,
            'state': self.states[self.current_step].copy(),
            'time': datetime.now().isoformat()
        })
        self._log(f"Snapshot saved: {snap_label}")

    def compare_snapshots(self, label1: str, label2: str) -> Dict:
        """Compare two snapshots."""
        s1 = next(s for s in self.snapshots if s['label'] == label1)
        s2 = next(s for s in self.snapshots if s['label'] == label2)
        fidelity = abs(np.vdot(s1['state'], s2['state']))**2
        return {
            'fidelity': float(fidelity),
            'step_diff': s2['step'] - s1['step'],
            'labels': (label1, label2)
        }

    def step(self) -> Optional[Dict]:
        """Execute one step."""
        if self.current_step >= len(self.circuit.data):
            return None
        self.current_step += 1
        inst, qargs, _ = self.circuit.data[self.current_step - 1]
        result = {
            'step': self.current_step,
            'gate': inst.name,
            'qubits': [q._index for q in qargs]
        }
        self._log(f"Step {self.current_step}: {inst.name}")
        return result

    def continue_to_breakpoint(self) -> Optional[int]:
        """Continue until breakpoint."""
        while self.current_step < len(self.circuit.data):
            self.current_step += 1
            if self.current_step in self.breakpoints:
                bp = self.breakpoints[self.current_step]
                if bp['enabled']:
                    bp['hits'] += 1
                    self._log(f"Hit breakpoint: {bp['name']}")
                    return self.current_step
        return None

    def run_to_gate(self, gate_index: int):
        """Run to specific gate."""
        self.current_step = min(gate_index, len(self.circuit.data))
        self._log(f"Jumped to gate {self.current_step}")

    def inspect_at(self, step: int) -> Dict:
        """Get detailed inspection at step."""
        state = self.states[step]
        amps = {}
        for i, amp in enumerate(state):
            if abs(amp) > 1e-10:
                basis = format(i, f'0{self.n_qubits}b')
                amps[basis] = {'amplitude': complex(amp), 'probability': abs(amp)**2}
        return {'step': step, 'amplitudes': amps, 'watches': self._eval_watches(state)}

    def get_watch_values(self) -> Dict:
        """Evaluate all watch expressions."""
        return self._eval_watches(self.states[self.current_step])

    def _eval_watches(self, state: np.ndarray) -> Dict:
        """Evaluate watches on given state."""
        results = {}
        for name, expr in self.watches.items():
            try:
                results[name] = expr(state)
            except Exception as e:
                results[name] = f"Error: {e}"
        return results

    def _log(self, message: str):
        """Add to session log."""
        self.log.append({'time': datetime.now().isoformat(), 'message': message})

    def generate_report(self) -> str:
        """Generate comprehensive debug report."""
        lines = []
        lines.append("="*70)
        lines.append(f"DEBUG SESSION REPORT: {self.name}")
        lines.append("="*70)
        lines.append(f"\nCircuit: {self.n_qubits} qubits, {len(self.circuit.data)} gates")
        lines.append(f"Current Step: {self.current_step}/{len(self.circuit.data)}")

        lines.append("\n" + "-"*70)
        lines.append("BREAKPOINTS:")
        for idx, bp in sorted(self.breakpoints.items()):
            lines.append(f"  Gate {idx}: {bp['name']} (hits: {bp['hits']})")

        lines.append("\n" + "-"*70)
        lines.append("SNAPSHOTS:")
        for snap in self.snapshots:
            lines.append(f"  {snap['label']} (step {snap['step']})")

        lines.append("\n" + "-"*70)
        lines.append("CURRENT WATCH VALUES:")
        for name, value in self.get_watch_values().items():
            lines.append(f"  {name}: {value}")

        lines.append("\n" + "-"*70)
        lines.append("CURRENT STATE:")
        state = self.states[self.current_step]
        for i, amp in enumerate(state):
            if abs(amp) > 1e-10:
                basis = format(i, f'0{self.n_qubits}b')
                lines.append(f"  |{basis}>: {amp:.4f} (p={abs(amp)**2:.4f})")

        return "\n".join(lines)
